# Base geometry classes

from types_data import Point2D
from interfaces import IProcessor

class Shape:
    _id: int

    def __init__(self, id: int):
        self._id = id

    def get_id(self) -> int:
        return self._id

    def get_name(self) -> str:
        return "Shape"

    def area(self) -> float:
        return 0.0

    def perimeter(self) -> float:
        return 0.0

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, id: int, w: float, h: float):
        super().__init__(id)
        self.width = w
        self.height = h

    def get_name(self) -> str:
        return "Rectangle"

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

class Square(Rectangle):
    def __init__(self, id: int, side: float):
        super().__init__(id, side, side)

    def get_name(self) -> str:
        return "Square"

class PointProcessor(IProcessor[Point2D, float]):
    def process(self, input: Point2D) -> float:
        return input.magnitude()

