# Extended shapes with additional functionality

from types_data import LogLevel
from geometry_base import Shape

class Circle(Shape):
    radius: float

    def __init__(self, id: int, r: float):
        super().__init__(id)
        self.radius = r

    def get_name(self) -> str:
        return "Circle"

    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    def log_message(self, level: int) -> str:
        if level == LogLevel.DEBUG.value:
            return f"Circle(r={self.radius})"
        return f"Circle with radius {self.radius}"

class ColoredBox[T](Box[T]):
    color: str

    def __init__(self, v: T, c: str):
        super().__init__(v)
        self.color = c

    def unwrap(self) -> T:
        return self.value

    def log_message(self, level: int) -> str:
        return f"[{self.color}] Box containing: {self.value}"

