# Primary utility functions and operations

from types_data import LogLevel, StatusCode, Point2D, NamedPoint, Box
from geometry_base import Shape, Rectangle, Square, PointProcessor
from shapes import Circle, ColoredBox

def compute_factorial(n: int) -> int:
    if n <= 1:
        return 1
    return n * compute_factorial(n - 1)

def filter_positive(nums: list[float]) -> list[float]:
    return [n for n in nums if n > 0.0]

def get_status_message(code: StatusCode) -> str:
    if code.value == StatusCode.SUCCESS.value:
        return "Operation successful"
    if code.value == StatusCode.NOT_FOUND.value:
        return "Resource not found"
    if code.value == StatusCode.ERROR_CODE.value:
        return "Internal server error"
    return "Unknown status"

def process_point(processor: PointProcessor, input: Point2D) -> float:
    return processor.process(input)

def get_shape_info(obj: Shape) -> str:
    return f"{obj.get_name()} (id={obj.get_id()})"

def create_named_point(name: str, x: float, y: float) -> NamedPoint:
    return NamedPoint(name, x, y)

class Aggregator:
    values: list[int]

    def __init__(self):
        self.values = []

    def add(self, v: int) -> None:
        self.values.append(v)

    def sum(self) -> int:
        result: int = 0
        for v in self.values:
            result = result + v
        return result

    def average(self) -> float:
        if len(self.values) == 0:
            return 0.0
        return float(self.sum()) / float(len(self.values))
